import 'dart:io';import 'package:flutter_test/flutter_test.dart';import 'package:oraculo_ia/src/features/content/data/knowledge_reader.dart';import 'package:oraculo_ia/src/features/manual_export/domain/manual_export.dart';void main(){test('exports complete markdown html and valid PDF',()async{final c=const KnowledgeReader().parse(File('knowledge/oraculo_content_v1.json').readAsStringSync());final e=const ManualExporter();expect(e.markdown(c),contains('Glosario'));expect(e.html(c),startsWith('<!doctype html>'));final bytes=await e.pdf(c);expect(String.fromCharCodes(bytes.take(4)),'%PDF');});}
